+            for j in 0..n {
+                let mut sum = 0.0;
+                for l in 0..k {
+                    sum += u[i * m + l] * s[l] * vt[l * n + j];
+                }
+                recon[i * n + j] = sum;
+            }
+        }
+        let a_norm: f64 = a.iter().map(|&x| x * x).sum::<f64>().sqrt();
+        let err: f64 = a
